import { Button } from '@material-ui/core'
import axios from 'axios'
import React, { useState } from 'react'
import { useNavigate } from 'react-router-dom'



export default function CreateAdmin() {
    const history = useNavigate();
    const [data, setData] = useState({
        firstName: '',
        lastName: '',
        studentID: '',
        password: ''
    })

    const handleChange = (event) => {
        const name = event.target.name;
        const value = event.target.value;

        setData(data => ({...data, [name]: value}));
    }

    const handleSubmit = (event) => {
        event.preventDefault();
        const sendData = {
            firstName:data.firstName,
            lastName:data.lastName,
            studentID:data.studentID,
            password:data.password
        }
        axios.post('http://localhost:80/api/register.php', sendData)
        .then((result) => {
            console.log(result.data)
            if(result.data.Status == 'Invalid') {
                alert('Invalid User');
            } else {
                console.log('Sent')
            }
        })
    };

    
   

  return (
    
    <div>
        
        <center>
        <h1>Register</h1>
        <form onSubmit={handleSubmit}>

            <label>First Name: </label>
            <input type="text" name='firstName' value={data.firstName} onChange={handleChange} />
            <br /><br />

            <label>Last Name: </label>
            <input type="text" name='lastName' value={data.lastName} onChange={handleChange} />
            <br /><br />
            

            <label>Student ID: </label>
            <input type="text" name='studentID' value={data.studentID} onChange={handleChange} />
            <br /><br />

            <label>Password: </label>
            <input type="password" name='password' value={data.password} onChange={handleChange} />
            <br /><br />

            <Button type='submit' name='submit' variant='contained' color='secondary' >Register</Button>

        </form>
        </center>
        
        <input type="file" onChange={(event) => {console.log(event.target.files[0])}} />
    </div>
  )
}
